// app.config.ts
import { provideImgixLoader } from '@angular/common';

export const appConfig: ApplicationConfig = {
  providers: [
    // Optional: register a CDN loader for automatic URL generation
    provideImgixLoader('https://cdn.example.com'),
  ]
};

// gallery.component.ts
import { Component } from '@angular/core';
import { NgOptimizedImage } from '@angular/common';

interface GalleryItem {
  src: string;
  alt: string;
  width: number;
  height: number;
}

@Component({
  selector: 'app-gallery',
  standalone: true,
  imports: [NgOptimizedImage],
  template: `
    <ul class="gallery">
      @for (item of items; track item.src) {
        <li class="gallery__item">
          <img
            [ngSrc]="item.src"
            [width]="item.width"
            [height]="item.height"
            [alt]="item.alt"
          />
        </li>
      }
    </ul>
  `,
  styles: [`
    .gallery {
      display: grid;
      grid-template-columns: repeat(auto-fill, minmax(200px, 1fr));
      gap: 1rem;
      list-style: none;
      padding: 0;
    }
    .gallery__item img {
      width: 100%;
      height: auto;
      display: block;
      border-radius: 4px;
    }
  `]
})
export class GalleryComponent {
  items: GalleryItem[] = [
    { src: 'photo-1.webp', alt: 'Angular component diagram', width: 400, height: 300 },
    { src: 'photo-2.webp', alt: 'TypeScript code editor screenshot', width: 400, height: 300 },
    { src: 'photo-3.webp', alt: 'Browser DevTools performance panel', width: 400, height: 300 },
  ];
}

// gallery.component.spec.ts
import { TestBed, ComponentFixture } from '@angular/core/testing';
import { GalleryComponent } from './gallery.component';
import { By } from '@angular/platform-browser';

describe('GalleryComponent', () => {
  let fixture: ComponentFixture<GalleryComponent>;

  beforeEach(async () => {
    await TestBed.configureTestingModule({
      imports: [GalleryComponent],
    }).compileComponents();
    fixture = TestBed.createComponent(GalleryComponent);
    fixture.detectChanges();
  });

  it('renders one img per gallery item', () => {
    const imgs = fixture.debugElement.queryAll(By.css('img'));
    expect(imgs.length).toBe(fixture.componentInstance.items.length);
  });

  it('sets alt text from item data', () => {
    const firstImg = fixture.debugElement.query(By.css('img'));
    expect(firstImg.nativeElement.getAttribute('alt'))
      .toBe(fixture.componentInstance.items[0].alt);
  });

  it('sets loading=lazy on non-priority images', () => {
    const imgs = fixture.debugElement.queryAll(By.css('img'));
    imgs.forEach(img => {
      expect(img.nativeElement.getAttribute('loading')).toBe('lazy');
    });
  });
});

// lazy-image.component.ts
import { Component, Input } from '@angular/core';
import { NgOptimizedImage } from '@angular/common';

@Component({
  selector: 'app-lazy-image',
  standalone: true,
  imports: [NgOptimizedImage],
  template: `
    <div class="wrapper" [class.loaded]="isLoaded">
      <img
        [ngSrc]="src"
        [width]="width"
        [height]="height"
        [alt]="alt"
        (load)="isLoaded = true"
      />
    </div>
  `,
  styles: [`
    .wrapper {
      background: #e5e7eb;
      animation: skeleton 1.2s ease-in-out infinite alternate;
    }
    @keyframes skeleton {
      from { background-color: #e5e7eb; }
      to   { background-color: #f3f4f6; }
    }
    .wrapper.loaded { animation: none; background: none; }
    img {
      display: block;
      width: 100%;
      height: auto;
      opacity: 0;
      transition: opacity 0.3s;
    }
    .loaded img { opacity: 1; }
  `]
})
export class LazyImageComponent {
  @Input({ required: true }) src!: string;
  @Input({ required: true }) alt!: string;
  @Input({ required: true }) width!: number;
  @Input({ required: true }) height!: number;
  isLoaded = false;
}
